cd /tmp/sv-0bd1ec86f34f4ce1937231cbfecbe67a/moderate-msbuild-properties && dotnet package list --format json 2>/dev/null | python3 -m json.tool > after-cpm-packages.json && python3 -c "
import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def extract(data):
    pkgs = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for p in fw['topLevelPackages']:
                pkgs[(name, p['id'])] = p['resolvedVersion']
    return pkgs

b = extract(baseline)
a = extract(after)

changes = []
for k in sorted(set(b.keys()) | set(a.keys())):
    bv = b.get(k, 'N/A')
    av = a.get(k, 'N/A')
    if bv != av:
        changes.append((k[0], k[1], bv, av))

if changes:
    print('CHANGES DETECTED:')
    for c in changes:
        print(f'  {c[0]} | {c[1]} | {c[2]} -> {c[3]}')
else:
    print('NO CHANGES - conversion is fully version-neutral')
    print()
    print('All packages:')
    for k in sorted(b.keys()):
        print(f'  {k[0]} | {k[1]} | {b[k]}')
"

